VALUES
  ('cpa-moex-00901', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司給與其100位行銷部門員工每人每年7天之累積帶薪休假，此100位員工之平均日薪為$2,000， 公司預估會有80%之休假天將在本年度被行使，截至本年3月31日止共有50天之休假實際發生， 則該公司於第一季之資產負債表應認列多少應付休假給付負債？', '["$0", "$180,000", "$250,000", "$280,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00902', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司與某客戶於20X1年10月簽訂銷售合約，約定於20X2年3月前以每單位$500提供300單位 商品予客戶，該商品之單位成本為$400，若遲延交貨達10天以上將針對遲延送達之單位提供40%之 折扣。20X1年底甲公司估計20X2年3月底前僅能交付100單位，其餘200單位4月底才能交付。 請問甲公司於20X1年底應認列該銷售合約之負債準備若干？', '["$0", "$10,000", "$20,000", "$40,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00903', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20Xl年1月1日發行可轉換公司債，該可轉換公司債的公允價值為$117,000，公司債面額 為$100,000，票面利率為1%，每年12月31日付息一次，發行期限為5年，轉換價格為$50。甲公司 發行時不含轉換權之公司債公允價值為$90,000，轉換權之公允價值為$30,000。甲公司在發行時，發 生$468直接交易成本（不考慮所得稅之影響），試問20X1年1月1日甲公司發行可轉換公司債分 錄中，「資本公積－認股權」之金額為何？', '["$26,532", "$26,892", "$27,000", "$30,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00904', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列有關退休金計畫之敘述，何者正確？', '["甲公司設有確定提撥之退休金計畫，並於每年6 月就前一年度應提撥之金額提撥退休準備金至員 工專戶。公司在每年期末應以折現基礎衡量其確定提撥之福利義務", "公司執行確定福利退休金計畫時，應認列於當期損益之項目包括：當期服務成本、前期服務成本、 清償損益、再衡量數、淨確定福利負債淨利息", "確定退職後福利計畫之精算假設應包含企業於未來破產之機率，以因應企業未來可能因破產清算 而無法支應員工退職後福利之情況", "企業修改退職後福利計畫時，其前期服務成本不包括先前假定之薪資增加與實際增加之差異，對 支付以前年度服務之福利義務之影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00905', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司自20X6年初將存貨成本公式由先進先出法改為加權平均法。20X4年底與20X5年底加權平 均法之存貨成本分別較先進先出法高出$400,000與$300,000；若所得稅率為17%，則20X6年初改變 會計政策之分錄應：', '["借記：追溯適用及追溯重編之影響數$83,000", "借記：追溯適用及追溯重編之影響數$249,000", "貸記：追溯適用及追溯重編之影響數$83,000", "貸記：追溯適用及追溯重編之影響數$249,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00906', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司之員工每人每年可有8天帶薪假，未使用之休假可延至次年使用，逾期則失效；員工若離職， 其未使用之休假亦失效，無法折抵現金補償。員工休假日之計算，首先由當年之休假日扣抵，其次 由前一年度未使用之休假日扣抵。20X1年12月31日，甲公司有80名員工，平均未休完之剩餘年 假為3天，平均日薪為$550。甲公司預期在20X2年之平均日薪為$600，將有5%的員工在未使用休 假前即已離職，70%的員工將休假11天，另25%的員工將休假10天。試問，甲公司在20X1年12月 31日應認列之相關負債為多少？', '["$114,400", "$124,800", "$144,000", "$132,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00907', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列何項交易可增加企業之營運資金？', '["購買透過損益按公允價值衡量之金融資產（分類為流動資產）", "支付應付帳款", "收取應收帳款", "現金增資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00908', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司將一批貨品售予乙公司，以下何種交易方式可認列收入？', '["甲公司與乙公司約定在特定日期將原貨品依約定價格（包括原賣價、利息費用及倉儲成本）買回", "甲公司對該貨品之瑕疵，承擔正常保固條件外之義務", "乙公司將商品再出售時甲公司方能收款", "分期付款銷售中，甲公司為確保債權而保留商品的法定所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00909', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司將自建一廠房。相關的支出如下：原料支出$100,000（含未享現金折扣$10,000），直接人工 成本$600,000，分攤的間接成本$40,000，自建廠房可以賺$40,000，建築師設計廠房支出$50,000，與 興建廠房專案借款有關的借貸成本$30,000，設算資金成本$40,000。自建廠房之成本為：', '["$820,000", "$780,000", "$810,000", "$860,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00910', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初收取現金對價$403,000，將分類為透過損益按公允價值衡量且將於20X1年底到 期之債券投資移轉予乙公司，該帳面金額$400,000，甲公司並對乙公司提供公允價值為$3,000之最高 賠償$40,000違約損失保證。甲公司既未移轉亦未保留該債券投資所有權之幾乎所有風險及報酬，且 約定乙公司不得自由出售該債券投資。關於移轉該債券投資對甲公司20X1年初財務報表之影響，下 列敘述何者正確（不考慮所得稅影響）？', '["備抵呆帳增加$40,000", "債券投資減少$360,000", "金融負債增加$43,000", "金融資產增加$43,000 淨利減少$3,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
